mapper.insert:
		INSERT INTO ARTFILE ( FILE_ID
			                , SEQ
							, SAVE_GB
							, FILE_PATH
							, ORGF_NM
							, SAVE_NM
							, FILE_EXT
							, FILE_TYPE
							, FILE_SIZE
							, TAG_NM
							, FILE_DESC
							, UPLOAD_DTTM
							, STTUS_CODE
							, CHG_USER_ID
							, CRT_DATE
							, CHG_DATE
		           ) VALUES ( #{fileId}
		                    , #{seq}
                            , #{saveGb}
                            , #{filePath}
                            , #{orgfNm}
                            , #{saveNm}
                            , #{fileExt}
                            , #{fileType}
                            , #{fileSize}
                            , #{tagNm}
                            , #{fileDesc}
                            , COALESCE(#{uploadDttm}, NOW())
                            , 'A'
                            , COALESCE(#{UNIQ_ID}, '')
                            , NOW()
                            , NOW()
		);

mapper.select:
SELECT COALESCE(MAX(A1.SEQ), 0)
  FROM ARTFILE A1
 WHERE A1.FILE_ID = #{fileId}

mapper.delete:
DELETE FROM ARTFILE
 WHERE FILE_ID = #{fileId}
   AND SEQ = #{seq}

mapper.update:
UPDATE ARTFILE
   SET SAVE_GB = #{saveGb}
     , FILE_PATH = #{filePath}
     , ORGF_NM = #{orgfNm}
     , SAVE_NM = #{saveNm}
     , FILE_EXT = #{fileExt}
     , FILE_TYPE = #{fileType}
     , FILE_SIZE = #{fileSize}
     , FILE_DESC = #{fileDesc}
     , UPLOAD_DTTM = COALESCE(#{uploadDttm}, NOW())
     , CHG_DATE = NOW()
 WHERE FILE_ID = #{fileId}
   AND SEQ = #{seq}

UPDATE ARTFILE
   SET FILE_DESC = #{fileDesc}
     , UPLOAD_DTTM = COALESCE(#{uploadDttm}, NOW())
     , CHG_DATE = NOW()
 WHERE FILE_ID = #{fileId}
   AND SEQ = #{seq}

UPDATE ARTFILE
   SET SEQ = #{toSeq}
     , CHG_DATE = NOW()
 WHERE FILE_ID = #{fileId}
   AND SEQ = #{fromSeq}
